public class SwapRef {
    static void swap(int[] a, int[] b) {
        int[] temp = a;
        a = b;         // reassigns local parameter
        b = temp;      // reassigns local parameter
    }
    public static void main(String[] args) {
        int[] x = {1};
        int[] y = {2};
        swap(x, y);
        System.out.println(x[0] + " " + y[0]);  // still 1 2
    }
}
